DELETE FROM sys_uav_equipment;

-- 重置自增ID（可选，从1开始）
ALTER TABLE sys_uav_equipment AUTO_INCREMENT = 1;
ALTER TABLE sys_uav_route AUTO_INCREMENT = 1;
ALTER TABLE sys_uav_task AUTO_INCREMENT = 1;
